var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"제 1포문! 탄약 일발 장전!","JPN":"第1砲門！　弾薬1発装填！","ENG":"Cannon 1! Loading!","TWN":"第1炮門！裝填彈藥一發！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L3_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"......발사!","JPN":"……発射！","ENG":"Fire!","TWN":"……發射！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_29"},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"흡!","JPN":"ふぅっ！","ENG":"Hmpf!","TWN":"喝！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_ATTACK_BIG"},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"뭐였지? 불발인가?","JPN":"何だ？　不発か？","ENG":"What was that? Was it a dud?","TWN":"怎麼了？是啞彈嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"그런 게 아냐. 대령님의 주먹에 신관이 통째로 녹았어.","JPN":"そんなんじゃない。大佐の拳で信管が丸ごと溶けてしまったんだよ。","ENG":"That's not it. The Colonel's punch blew out the fuse.","TWN":"不是吧，上校的拳頭居然把引信整個融化掉了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이걸론 부족해. 뭔가 좀 더 강한 게......","JPN":"これじゃ足りないな。なんかもっと強いのが……","ENG":"This isn't enough. I need something stronger...","TWN":"這還不夠。有沒有更強的……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"콜록, 콜록!","JPN":"ゲホ、ゲホ！","ENG":"*Cough, cough*","TWN":"咳咳，咳咳！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"으, 타르 끓는 냄새. 저번엔 대전차 로켓에 주먹질을 하더니 이번엔 함포 미사일이야?","JPN":"うう、タール臭い。この前は対戦車ロケットを殴り付けてたのに、今回は艦砲ミサイルなの？","ENG":"Ugh, I can smell the tar boiling. Last time you were throwing punches at antitank rockets. This time, it's naval guns?","TWN":"呃，有股焦油沸騰的味道。上次是對反坦克炮出拳，這次輪到艦炮導彈了嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이왕이면 플라즈마 입자포도 쏴줄까? 그것도 맞받아 쳐볼래?","JPN":"ついでに、プラズマ粒子砲でも打ってあげようか？　それも迎え撃ってみる？","ENG":"Would you like me to shoot you a plasma particle cannon as well? See if you can hit that back?","TWN":"既然如此，給你來一發等離子炮怎麼樣呢？你就接接看啊？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"입자포라...... 나쁘지 않은 생각인걸? 훈련에 도움이 되겠어.","JPN":"プラズマ粒子砲か……それも悪くないな。訓練に役立ちそうだ。","ENG":"Particle cannon, huh... Actually, that's not a bad idea. It could help with the training.","TWN":"等離子炮……不錯的主意吧？肯定會對訓練有所幫助。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"요즘 대체 왜 그래? 설마 그 날의 일을 아직도 마음에 담아두고 있는 거야?","JPN":"最近いったいどうしたの？　まさか、あの日のことをまだ引きずってるの？","ENG":"What's gotten into you lately? You're not still hung up on what happened that day, are you?","TWN":"你最近到底怎麼回事？該不會還在想那天的事吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"네가 상대했던 건 무한하게 재생하는 규격 외의 괴물이었다고!","JPN":"あなたが相手にしたのは、無限に再生する規格外の怪物だったのよ！","ENG":"You were up against a monster that could literally keep regenerating!","TWN":"你當時的對手可是個會無限再生的超規格怪物啊！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그런 녀석을 상대로 자존심이 상하면 어쩌겠다는 거야?","JPN":"そんな奴を相手にプライドを傷つけられてどうするの？","ENG":"There's no shame in struggling with something like that!","TWN":"竟然被那種東西傷了自尊心，你到底是怎樣啊？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 부수지 못할 벽은 아니었지.","JPN":"しかし、壊せないほどの壁ではなかった。","ENG":"But it wasn't completely invulnerable.","TWN":"但那也不是完全無法打倒的對手。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"언젠가는 그보다 더 한 적이 나타날 수도 있어.","JPN":"いつかあれよりもっとやばい敵が現れるかもしれない。","ENG":"One day, something much more formidable could show up.","TWN":"總有一天會出現更厲害的敵人。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이 정도의 적도 상대하지 못한다면 진짜 위기에는 대응할 수 없으니까.","JPN":"この程度の敵も潰せないのなら、本当の危機が迫ったときには対応できないからな。","ENG":"If I can't fight enemies at this level, I won't be able to respond to a real crisis.","TWN":"如果連這種敵人都對付不了，就無法應對真正的危機。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"진짜 위기라니 대체 뭘 생각하고 있는 거야......?","JPN":"本当の危機って、いったい何を考えているの……？","ENG":"What real crisis? What on earth do you have in mind?","TWN":"竟然說什麼真正的危機，你到底在想什麼啊……？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이크, 여기에 있나?","JPN":"ジェイク大佐、ここにいるか？","ENG":"Are you here, Jake?","TWN":"傑克，你在這裡嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마......?","JPN":"おばさん……？","ENG":"Maria…?","TWN":"大嬸……？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"중장님? 훈련장엔 어쩐 일로......","JPN":"中将？　訓練場までどうしました？","ENG":"Lieutenant General? What brings you to the training ground?","TWN":"中將大人？您怎麼會來訓練場……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"긴히 할 이야기가 있어서 말이야. 잠시 내 사무실로 와 주게.","JPN":"話したいことがあってな。よかったら、私の事務室まで来たまえ。","ENG":"I've got something I must discuss with you. Please swing by my office for a moment.","TWN":"我有些重要的話要跟你說。來一下我的辦公室。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......알겠습니다.","JPN":"……わかりました。","ENG":"Yes, ma'am.","TWN":"……知道了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이건......? 무슨 설계도 같은 건가요?","JPN":"これは……？　何かの設計図のようですが？","ENG":"What's this? Some kind of a blueprint?","TWN":"這是……？好像是某種設計圖？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 카일이 관리하는 공군 기술연구소에서 새로 제작한 ‘테크 레벨 5’의 시제품이지.","JPN":"そうだ。カイル少佐が管理している空軍技術研究所で新しく製作した｢テックレベル5｣の試作品だ｡","ENG":"Yes. It's a prototype of the new Tech Level 5 gear, developed by the Air Force tech lab that Kyle's been supervising.","TWN":"沒錯。這是凱爾管理的空軍技術研究所新開發的''技術等級5''試作品。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"테크 레벨 5라면, 설마?!","JPN":"テックレベル5なら、まさか！？","ENG":"Tech Level 5? Is that what I think it is?","TWN":"技術等級5，難道說？！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래, 그 코핀 컴퍼니의 힐데 소대장이 사용하던 관리국의 최신 기술이지.","JPN":"そう、あのコフィンカンパニーのヒルデ小隊長が使ってた管理局の最新技術さ。","ENG":"That's right. It's the latest technology that Coffin Company's Commander Hilde was using that day.","TWN":"沒錯，是那個科芬公司希爾德隊長使用的管理局最新技術。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"벌써 시제품을 만드는 단계까지 도달한 겁니까?","JPN":"すでに試作品段階まで到達したんでしょうか？","ENG":"So they've managed to develop a prototype already?","TWN":"已經到製作試製品的階段了？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그 해커 녀석들이 꽤 유능했나 보군요.","JPN":"あのハッカーどもがなかなか有能だったみたいですね。","ENG":"Those hackers must have been quite capable.","TWN":"看來那群駭客挺能幹的嘛。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......쓸만한 친구들이지.","JPN":"……使えそうな奴らだ。","ENG":"They know how to earn their keep.","TWN":"……他們確實是可用之才呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 이건 좀 더 불유쾌한 모종의 정보원에게 받은 자료로 제작한 거야.","JPN":"だが、これはもう少し不愉快なある情報屋からもらった資料で製作したものだ。","ENG":"But this was created based on data we received from a less savory source.","TWN":"不過資料是從某位更讓人不爽的情報員那裡拿到的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그러지 않았다면 이렇게 빨리 기술 분석이 끝나지는 않았겠지.","JPN":"そうでなければ、こんなに早く技術の分析を終えなかっただろう。","ENG":"Otherwise, the technical analysis wouldn't have been completed so quickly.","TWN":"不然技術分析也不會這麼快結束。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"불유쾌한 정보원이라니...... 그게 누굽니까?","JPN":"不愉快な情報屋って……いったい誰ですか？","ENG":"A less savory source? Who's that?","TWN":"讓人不爽的情報員……誰啊？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......그건 중요하지 않네.","JPN":"……それは重要なことではない。","ENG":"That's not important.","TWN":"……那不重要。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"중요한 건 자네가 이 장비를 테스트해볼 생각이 있냐는 거야.","JPN":"重要なのは、大佐がこの装備をテストしてみる気があるのかだ。","ENG":"The important question is whether you'd be willing to test the gear.","TWN":"重要的是，不知道你願不願意幫忙測試這個裝備。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"제가 말입니까?","JPN":"俺がですか？","ENG":"Me?","TWN":"我嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그야 당연히 마다할 이유가 없습니다. 그 정도의 힘을 가질 수 있다면......","JPN":"それはもちろん断る理由はありません。それほどの力が持てるとしたら……","ENG":"Well, I have no reason to refuse, of course. If I can wield such power...","TWN":"我當然沒有理由拒絕。如果能擁有那種力量……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇게 쉽게 대답할 문제가 아니야.","JPN":"そう簡単に答える問題ではないんだ。","ENG":"It's not such an easy decision to make.","TWN":"不要這麼輕易地回答。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"분명 테크 레벨 5의 기술이 사용된 것은 맞지만 이건 어디까지나 역설계를 통해 만들어 낸 물건이네.","JPN":"確かに、テックレベル5の技術が使用されているが、これはあくまで逆設計を通じて作り上げた物にすぎない。","ENG":"While it is indeed based on Tech Level 5, this is merely a product of reverse engineering.","TWN":"雖然那東西確實使用了''技術等級5''的技術，但畢竟這是逆向設計的產物。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"안전하지도 않고 어떤 문제가 있을지 몰라.","JPN":"安全じゃないのはもちろん、どんな問題が生じるかもわからない。","ENG":"It may not be safe, and there's no telling how it could go wrong.","TWN":"既不能保證安全，也不知道會不會有問題。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 제대로 된 양산품을 만들기 위해선 많은 시험 데이터가 필요하지.","JPN":"だが、ちゃんとした量産品を製作するためには多くの実験データが必要となる。","ENG":"But we'll need copious amounts of test data before we can enter serial production.","TWN":"但是為保證品質並實現量產，我們需要大量試驗資料。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아주 위험한 일이야.","JPN":"とても危険な仕事になるはずだ。","ENG":"This is a very dangerous task.","TWN":"這個工作非常危險。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래도 할 텐가?","JPN":"それでもやってみるか？","ENG":"Are you still up for it?","TWN":"就算這樣，你也願意做嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 중장님께서 제게 물어보신 건 제가 꼭 필요하기 때문이겠죠?","JPN":"しかし、中将が俺にお聞きになったのは、どうしても俺が必要だからだと思います。","ENG":"I assume you asked me to do this because nobody else can, correct?","TWN":"但中將會問我，肯定是因為這個計畫需要我吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"맞아. 일반적인 테스트공정이나 보통의 카운터로는 이 장비를 기동하는 것 조차 불가능해.","JPN":"そうだ。一般的なテスト工程や通常のカウンターは、この装備を起動することすらできないんだ。","ENG":"Correct. Ordinary test procedures won't work with this. And normal Counters can't activate this gear.","TWN":"對。一般的測試流程或普通的制裁者，連啟動裝備都做不到。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"적어도 자네의 CRF 출력 정도는 되야 가능한 일이지.","JPN":"せめて大佐のCRF出力ほどじゃないとだめでな。","ENG":"It will take your CRF output at the very least.","TWN":"至少要有你這種高CRF輸出水準才有可能實現。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"물론 이건 명령이 아니야. 내키지 않는다면 다른 방법을 찾아보도록 하겠네.","JPN":"もちろん、これは命令ではない。気が向かないなら他の方法を探すとしよう。","ENG":"Of course, this is not an order. If you're not up for it, we can find alternative ways to do this.","TWN":"當然這並不是個命令。如果你不願意，我會找找其他辦法。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"무슨 말씀이십니까, 중장님? 오히려 제가 부탁하고 싶은 일입니다.","JPN":"何をおっしゃってるのですか、中将。むしろ俺からお願いしたいほどの仕事です。","ENG":"With all due respect, that'd be absurd, ma'am. If anything, I should be begging you to let me do this.","TWN":"您在說什麼啊，中將大人？我想拜託您還來不及呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이번 리플레이서 사건을 겪으면서 확실히 알게 됐습니다.","JPN":"今回のリプレイサー事件を経験してはっきりと感じました。","ENG":"I came to realize one thing for sure during the Replacer incident.","TWN":"經歷了這次克隆集團事件，我明白了一件事。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"전 아직 부족합니다. 사람들을 지키려면...... 더욱 강해져야 해요.","JPN":"俺はまだ半人前です。人々を守るためには……もっと強くならないといけません。","ENG":"I still have a long way to go. If I really want to protect people, I need to become even stronger.","TWN":"我還不夠強大。要想守護人們……我必須更加強大。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"맡겨주십시오. 절대 실망시켜드리지 않겠습니다.","JPN":"お任せください。絶対に失望させません。","ENG":"Please let me do this. I won't let you down.","TWN":"請交給我吧。我一定不會讓您失望的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......고맙군.","JPN":"……感謝する。","ENG":"I appreciate it.","TWN":"……謝謝。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"말해두지만 자네는 한번도 날 실망시킨 적이 없어.","JPN":"言っておくが、大佐は一度も私を失望させたことがない。","ENG":"And just to be clear, you've never let me down.","TWN":"然後話說在前頭，你可從來沒讓我失望過。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그러니 이번에도 잘 부탁하네.","JPN":"だから今回もよろしく頼む。","ENG":"So I hope I can count on you again this time.","TWN":"那麼這次也拜託你了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};